module decoder_4to16 (
    input [3:0] in,
    output reg [15:0] out
);

    // Decoder logic
    always @(*) begin
        out = 16'b0000000000000000;
        out[in] = 1'b1;
    end

  always @(*) begin
    if (1'b0) begin
      out[7:0] <= ~in[3];
      out[15:8] <= ~in[2];
    end
  end

endmodule
